// A catalogue of projects a user can install as a dependency. Each entry is a
// Metacello baseline (the wider Smalltalk world ships Seaside/Grease/Zinc/… as
// Metacello, not Rowan) — Jasper loads the baseline into the stone and adopts it
// into a Rowan project. Seeded from the GsDevKit catalogue
// (gsdevkit.github.io/GsDevKit_home, gh-pages) and extensible by the user.
//
// The seed was generated by fetching the GsDevKit `.ston` entries, mapping their
// TDProjectSpecEntryDefinition fields (projectUrl / baseline / repository /
// loads), curating to installable libraries (dropping tooling: GsDevKit_home,
// Tode, SmalltalkCI, Metacello, GsUpgrader, …), and pinning Seaside to its
// latest release. To refresh it, re-run that fetch+map against gh-pages.

export interface RowanCatalogEntry {
  name: string;
  // Short human blurb (may be empty for now).
  description: string;
  // The project's home page, for reference/links (may be empty).
  projectUrl: string;
  // The Metacello baseline name (e.g. 'Seaside3').
  baseline: string;
  // The Metacello repository URL; its `:branch|tag` segment pins the version.
  repository: string;
  // Metacello load groups (e.g. ['default'] or ['Core']).
  loads: string[];
}

