// The full catalogue: the seed plus the user's own entries. A user entry with
// the same name overrides the seed (so the seed can be tweaked locally). Pure —
// the caller supplies the user entries (persisted in globalState).
export function mergeCatalog(userEntries: readonly RowanCatalogEntry[] = []): RowanCatalogEntry[] {
  const byName = new Map<string, RowanCatalogEntry>();
  for (const e of CATALOG_SEED) byName.set(e.name, e);
  for (const e of userEntries) byName.set(e.name, e);
  return [...byName.values()].sort((a, b) => a.name.localeCompare(b.name));
}
